  test('postgres workflow HTTP request port validates allowlist, fetches, and resumes workflows', async () => {
    const now = new Date('2026-06-03T12:40:00.000Z');
    const { db, rows } = makeAiReplySuggestionDb({
      syncInfo: [{
        workspace_id: WORKSPACE_A_ID,
        key: 'workflow_http_allowlist',
        value: 'api.example.com',
      }],
    });
    const fetchCalls: unknown[] = [];
    const port = createPostgresWorkflowHttpRequestPort({
      db,
      now: () => now,
      applyWorkspaceSession: async () => undefined,
      lookup: async (hostname) => {
        expect(hostname).toBe('api.example.com');
        return [{ address: '93.184.216.34' }];
      },
      fetchImpl: async (url, init) => {
        fetchCalls.push({ url, init });
        return {
          ok: true,
          status: 201,
          async text() {
            return 'created';
          },
        };
      },
    });

    await port.request({
      workspaceId: WORKSPACE_A_ID,
      messageId: 11,
      method: 'POST',
      url: 'https://api.example.com/hook',
      body: '{"ok":true}',
      timeoutMs: 5000,
      idempotencyKey: 'workflow-http-stable-key',
      continuation: {
        workflowId: 23,
        triggerName: 'inbound',
        resumeNodeId: 'tag-1',
        eventVariables: { 'message.id': 11 },
      },
    });

    expect(fetchCalls).toHaveLength(1);
    expect(fetchCalls[0]).toMatchObject({
      url: 'https://api.example.com/hook',
      init: {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Idempotency-Key': 'workflow-http-stable-key',
        },
        body: '{"ok":true}',
      },
    });
    expect(rows.jobs).toEqual([
      expect.objectContaining({
        type: 'workflow.execute',
        workspace_id: WORKSPACE_A_ID,
        run_after: now,
        max_attempts: 3,
      }),
    ]);
    expect(rows.jobs[0]?.payload).toEqual({
      workspaceId: WORKSPACE_A_ID,
      workflowId: 23,
      messageId: 11,
      triggerName: 'inbound',
      context: {
        resumeNodeId: 'tag-1',
        eventStrings: {},
        eventVariables: {
          'message.id': 11,
          'http.status': 201,
          'http.body': 'created',
          'http.ok': true,
        },
      },
    });

    await expect(port.request({
      workspaceId: WORKSPACE_A_ID,
      method: 'GET',
      url: 'https://evil.example.net/hook',
      timeoutMs: 5000,
    })).rejects.toThrow('allowlist');
  });

