      entityType: 'email_account',
      entityId: '1',
      payload: {
        fields: ['displayName', 'emailAddress', 'imapSyncSent', 'requestReadReceipt', 'smtpHost', 'syncSpamFolderPath', 'vacationBodyText'],
        passwordChanged: { imap: false, smtp: true },
      },
