function makeFetchResponse(input: {
  status?: number;
  text?: string;
  json?: unknown;
} = {}): Response {
  const status = input.status ?? 200;
  const text = input.text ?? '';
  return {
    ok: status >= 200 && status < 300,
    status,
    text: async () => text,
    json: async () => input.json ?? {},
  } as Response;
}

